const WORK_TIME = 45;
const REST_TIME = 30;
const WARMUP_TIME = 30;
const WARMUP_REST = 15;

// ── Áudio: beep de metrônomo via Web Audio API ───────────────────────────
function useMetronome(active) {
  const ctxRef  = useRef(null);
  const timerRef = useRef(null);

  const beep = () => {
    try {
      if (!ctxRef.current || ctxRef.current.state === "closed") {
        ctxRef.current = new (window.AudioContext || window.webkitAudioContext)();
      }
      const ctx = ctxRef.current;
      if (ctx.state === "suspended") ctx.resume();
      const osc  = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = "sine";
      osc.frequency.setValueAtTime(880, ctx.currentTime);
      gain.gain.setValueAtTime(0.35, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.08);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.08);
    } catch(e) {}
  };

  useEffect(() => {
    if (active) {
      beep();
      timerRef.current = setInterval(beep, 1000);
    } else {
      clearInterval(timerRef.current);
    }
    return () => clearInterval(timerRef.current);
  }, [active]);
}

// ── Cronômetro de Aquecimento ─────────────────────────────────────────────
function WarmupTimer({ warmupList, stationColor, onComplete }) {
  const [phase, setPhase] = useState("idle");
  const [timeLeft, setTimeLeft] = useState(WARMUP_TIME);
  const [currentIdx, setCurrentIdx] = useState(0);
  const ref = useRef(null);

  // metrônomo durante execução
  useMetronome(phase === "work");

  useEffect(() => () => clearTimeout(ref.current), []);

  useEffect(() => {
    if (phase !== "work" && phase !== "rest") return;
    if (timeLeft > 0) {
      ref.current = setTimeout(() => setTimeLeft((t) => t - 1), 1000);
    } else {
      if (phase === "work") {
        const next = currentIdx + 1;
        if (next >= warmupList.length) {
          setPhase("done");
          onComplete && onComplete();
        } else {
          setPhase("rest");
          setTimeLeft(WARMUP_REST);
        }
      } else {
        // intervalo acabou → vai direto pro próximo exercício sem GO
        setCurrentIdx((i) => i + 1);
        setPhase("work");
        setTimeLeft(WARMUP_TIME);
      }
    }
    return () => clearTimeout(ref.current);
  }, [phase, timeLeft]);

  const handleStart = () => { setPhase("work"); setTimeLeft(WARMUP_TIME); };
  const handlePause = () => { clearTimeout(ref.current); setPhase("idle"); };
  // handleGo não é mais necessário (automático), mantido por compatibilidade
  const handleGo = () => {};

  const isWork = phase === "work";
  const isRest = phase === "rest";
  const isIdle = phase === "idle";

  const timerColor = isWork ? "#E53E3E" : isRest ? "#3D8EF0" : "#404040";
  const total = isWork ? WARMUP_TIME : WARMUP_REST;
  const pct   = isIdle ? 0 : ((total - timeLeft) / total) * 100;
  const r = 72;
  const circ = 2 * Math.PI * r;
  const safeIdx = Math.min(currentIdx, warmupList.length - 1);
  const nextIdx = Math.min(currentIdx + 1, warmupList.length - 1);

  return (
    <div style={{
      background: "#050505",
      border: `2px solid ${timerColor}50`,
      borderRadius: 24, padding: "24px 20px",
      textAlign: "center",
      boxShadow: `0 0 40px ${timerColor}15`,
      transition: "border-color 0.4s, box-shadow 0.4s",
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
        <span style={{ fontSize: 11, color: "#4A4A4A", letterSpacing: 2, textTransform: "uppercase" }}>Aquecimento</span>
        <span style={{ fontSize: 12, fontWeight: 700, color: stationColor }}>
          {Math.min(currentIdx + 1, warmupList.length)} / {warmupList.length}
        </span>
      </div>

      <div style={{ fontSize: 17, fontWeight: 900, color: "#fff", letterSpacing: 0.5, marginBottom: 4, minHeight: 26 }}>
        {warmupList[safeIdx]}
      </div>
      <div style={{ fontSize: 12, color: "#404040", fontFamily: "Barlow, sans-serif", marginBottom: 18, minHeight: 18 }}>
        {isRest && currentIdx + 1 < warmupList.length
          ? <span>A seguir: <span style={{ color: "#505050" }}>{warmupList[nextIdx]}</span></span>
          : " "}
      </div>

      <div style={{ position: "relative", width: 190, height: 190, margin: "0 auto" }}>
        <svg width={190} height={190} style={{ transform: "rotate(-90deg)" }}>
          <circle cx={95} cy={95} r={r} fill="none" stroke="#1C1C1C" strokeWidth={11} />
          <circle cx={95} cy={95} r={r} fill="none"
            stroke={timerColor} strokeWidth={11}
            strokeDasharray={circ}
            strokeDashoffset={circ - (pct / 100) * circ}
            strokeLinecap="round"
            style={{ transition: "stroke-dashoffset 1s linear, stroke 0.4s" }} />
        </svg>
        <div style={{
          position: "absolute", inset: 0,
          display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center",
        }}>
          {isIdle ? (
            <span style={{ fontSize: 38, color: "#333" }}>▶</span>
          ) : (
            <>
              <span style={{ fontSize: 54, fontWeight: 900, color: "#fff", fontFamily: "monospace", lineHeight: 1 }}>
                {String(timeLeft).padStart(2, "0")}
              </span>
              <span style={{ fontSize: 11, color: timerColor, letterSpacing: 2, marginTop: 4 }}>seg</span>
            </>
          )}
        </div>
      </div>

      <div style={{
        fontSize: 16, fontWeight: 800, letterSpacing: 4,
        color: timerColor, textTransform: "uppercase",
        marginTop: 14, marginBottom: 20, minHeight: 24,
        transition: "color 0.4s",
      }}>
        {isWork ? "EXECUÇÃO" : isRest ? "INTERVALO · 15s" : ""}
      </div>

      <div style={{ display: "flex", gap: 10 }}>

        {(isWork || isRest) && (
          <button onClick={handlePause} style={{
            flex: 1, padding: "14px", borderRadius: 14, cursor: "pointer",
            background: "#1C1C1C", border: "1px solid #333", color: "#BBBBBB",
            fontSize: 15, fontWeight: 700,
          }}>⏸ PAUSAR</button>
        )}
        {isIdle && (
          <button onClick={handleStart} style={{
            flex: 1, padding: "16px", borderRadius: 14, cursor: "pointer",
            background: "#E53E3E", border: "none", color: "#ffffff",
            fontSize: 16, fontWeight: 800,
          }}>
            {currentIdx === 0 ? "▶ INICIAR" : "▶ RETOMAR"}
          </button>
        )}
      </div>

      <div style={{ display: "flex", gap: 5, marginTop: 18, justifyContent: "center", flexWrap: "wrap" }}>
        {warmupList.map((_, i) => (
          <div key={i} style={{
            width: 8, height: 8, borderRadius: "50%",
            background: i < currentIdx ? stationColor
                      : i === currentIdx && isWork ? "#E53E3E"
                      : "#232323",
            border: `1px solid ${i < currentIdx ? stationColor : i === currentIdx ? "#4A4A4A" : "#333"}`,
            transition: "all 0.3s",
          }} />
        ))}
      </div>
    </div>
  );
}

// ── Cronômetro Bilateral (D/E ou prancha) ────────────────────────────────
// Sequência por série: work_D(30s) → work_E(30s) → rest(30s) → GO
// Para plank: work_D(30s) → work_E(30s) → rest(30s) → GO  (mesmo fluxo)
const BILATERAL_TIME = 30;
const BILATERAL_REST = 10;

function BilateralTimer({ exercise, totalSets, stationColor, onComplete }) {
  const bTime = exercise.workTime || BILATERAL_TIME;
  // subPhase: "idle" | "side_a" | "adjust" | "side_b" | "rest" | "go"
  // side_a(Xs) → adjust(10s troca de lado) → side_b(Xs) → rest(30s entre séries) → go
  const [subPhase, setSubPhase] = useState("idle");
  const [timeLeft, setTimeLeft]  = useState(bTime);
  const [setsDone, setSetsDone]  = useState(0);
  const ref = useRef(null);

  const isPlank = exercise.plank === true;
  const labelA = isPlank ? "LADO DIREITO" : "PERNA DIREITA";
  const labelB = isPlank ? "LADO ESQUERDO" : "PERNA ESQUERDA";

  // metrônomo apenas durante execução
  useMetronome(subPhase === "side_a" || subPhase === "side_b");

  useEffect(() => () => clearTimeout(ref.current), []);

  useEffect(() => {
    const active = ["side_a", "adjust", "side_b", "rest"].includes(subPhase);
    if (!active) return;
    if (timeLeft > 0) {
      ref.current = setTimeout(() => setTimeLeft((t) => t - 1), 1000);
    } else {
      if (subPhase === "side_a") {
        // troca de lado: 10s para se ajustar
        setSubPhase("adjust");
        setTimeLeft(BILATERAL_REST); // 10s
      } else if (subPhase === "adjust") {
        // começa perna esquerda
        setSubPhase("side_b");
        setTimeLeft(bTime);
      } else if (subPhase === "side_b") {
        const next = setsDone + 1;
        setSetsDone(next);
        if (next >= totalSets) {
          setSubPhase("idle");
          onComplete && onComplete();
        } else {
          // intervalo entre séries: 30s
          setSubPhase("rest");
          setTimeLeft(REST_TIME);
        }
      } else {
        // rest entre séries → go
        setSubPhase("go");
      }
    }
    return () => clearTimeout(ref.current);
  }, [subPhase, timeLeft]);

  const handleStart = () => { setSubPhase("side_a"); setTimeLeft(bTime); };
  const handlePause = () => { clearTimeout(ref.current); setSubPhase("idle"); };
  const handleGo    = () => { setSubPhase("side_a"); setTimeLeft(bTime); };

  const isSideA  = subPhase === "side_a";
  const isAdjust = subPhase === "adjust";
  const isSideB  = subPhase === "side_b";
  const isRest   = subPhase === "rest";
  const isGo     = subPhase === "go";
  const isIdle   = subPhase === "idle";
  const isActive = isSideA || isAdjust || isSideB || isRest;

  const timerColor = isSideA  ? "#E53E3E"
                   : isAdjust ? "#3D8EF0"
                   : isSideB  ? "#2ECC71"
                   : isRest   ? "#3D8EF0"
                   : isGo     ? "#2ECC71"
                   : "#404040";

  const total = (isAdjust) ? BILATERAL_REST
              : isRest     ? REST_TIME
              : bTime;
  const pct   = isGo ? 100 : isIdle ? 0 : ((total - timeLeft) / total) * 100;
  const r = 72;
  const circ = 2 * Math.PI * r;

  const sideLabel = isSideA  ? labelA
                  : isAdjust ? `AJUSTE · ${labelB}`
                  : isSideB  ? labelB
                  : isRest   ? "INTERVALO · 30s"
                  : isGo     ? "PRÓXIMA SÉRIE!"
                  : "";

  return (
    <div style={{
      background: "#050505",
      border: `2px solid ${timerColor}50`,
      borderRadius: 24, padding: "24px 20px",
      textAlign: "center",
      boxShadow: `0 0 40px ${timerColor}15`,
      transition: "border-color 0.4s, box-shadow 0.4s",
    }}>
      {/* Nome + série */}
      <div style={{ fontSize: 20, fontWeight: 900, color: "#FFFFFF", letterSpacing: 1, marginBottom: 4 }}>
        {exercise.name}
      </div>
      <div style={{ fontSize: 12, color: "#4A4A4A", letterSpacing: 3, marginBottom: 16 }}>
        SÉRIE {Math.min(setsDone + 1, totalSets)} / {totalSets}
      </div>

      {/* Indicador de lados */}
      <div style={{ display: "flex", gap: 8, justifyContent: "center", marginBottom: 18 }}>
        {[labelA, labelB].map((lbl, i) => {
          const active = (i === 0 && isSideA) || (i === 1 && isSideB);
          const done   = (i === 0 && (isAdjust || isSideB || isRest || isGo))
                      || (i === 1 && (isRest || isGo));
          return (
            <div key={lbl} style={{
              flex: 1, padding: "8px 6px", borderRadius: 10, fontSize: 11,
              fontWeight: 800, letterSpacing: 1, textTransform: "uppercase",
              background: active ? timerColor : done ? `${stationColor}20` : "#161616",
              color: active ? (i === 0 ? "#fff" : "#000") : done ? stationColor : "#404040",
              border: `1px solid ${active ? timerColor : done ? stationColor + "40" : "#222"}`,
              transition: "all 0.3s",
            }}>{lbl}</div>
          );
        })}
      </div>

      {/* Círculo */}
      <div style={{ position: "relative", width: 190, height: 190, margin: "0 auto" }}>
        <svg width={190} height={190} style={{ transform: "rotate(-90deg)" }}>
          <circle cx={95} cy={95} r={r} fill="none" stroke="#1C1C1C" strokeWidth={11} />
          <circle cx={95} cy={95} r={r} fill="none"
            stroke={timerColor} strokeWidth={11}
            strokeDasharray={circ}
            strokeDashoffset={circ - (pct / 100) * circ}
            strokeLinecap="round"
            style={{ transition: "stroke-dashoffset 1s linear, stroke 0.4s" }} />
        </svg>
        <div style={{
          position: "absolute", inset: 0,
          display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center",
        }}>
          {isGo ? (
            <span style={{
              fontSize: 64, fontWeight: 900, color: "#2ECC71",
              fontFamily: "Barlow Condensed, sans-serif",
              animation: "goAnim 0.5s ease-in-out infinite alternate",
            }}>GO!</span>
          ) : isIdle ? (
            <span style={{ fontSize: 38, color: "#333" }}>▶</span>
          ) : (
            <>
              <span style={{ fontSize: 54, fontWeight: 900, color: "#fff", fontFamily: "monospace", lineHeight: 1 }}>
                {String(timeLeft).padStart(2, "0")}
              </span>
              <span style={{ fontSize: 11, color: timerColor, letterSpacing: 2, marginTop: 4 }}>seg</span>
            </>
          )}
        </div>
      </div>

      {/* Label */}
      <div style={{
        fontSize: 15, fontWeight: 800, letterSpacing: 3,
        color: timerColor, textTransform: "uppercase",
        marginTop: 14, marginBottom: 20, minHeight: 24,
        transition: "color 0.4s",
      }}>{sideLabel}</div>

      {/* Botões */}
      <div style={{ display: "flex", gap: 10 }}>
        {isGo && (
          <button onClick={handleGo} style={{
            flex: 1, padding: "16px", borderRadius: 14, cursor: "pointer",
            background: "#2ECC71", border: "none", color: "#000",
            fontSize: 22, fontWeight: 900, letterSpacing: 2,
            animation: "goAnim 0.5s ease-in-out infinite alternate",
          }}>🔥 GO!</button>
        )}
        {isActive && !isAdjust && (
          <button onClick={handlePause} style={{
            flex: 1, padding: "14px", borderRadius: 14, cursor: "pointer",
            background: "#1C1C1C", border: "1px solid #333", color: "#BBBBBB",
            fontSize: 15, fontWeight: 700,
          }}>⏸ PAUSAR</button>
        )}
        {isIdle && (
          <button onClick={handleStart} style={{
            flex: 1, padding: "16px", borderRadius: 14, cursor: "pointer",
            background: "#E53E3E", border: "none", color: "#ffffff",
            fontSize: 16, fontWeight: 800,
          }}>
            {setsDone === 0 ? "▶ INICIAR" : "▶ RETOMAR"}
          </button>
        )}
      </div>

      {/* Bolinhas séries */}
      <div style={{ display: "flex", gap: 8, marginTop: 18, justifyContent: "center" }}>
        {Array.from({ length: totalSets }, (_, i) => (
          <div key={i} style={{
            width: 10, height: 10, borderRadius: "50%",
            background: i < setsDone ? stationColor : "#232323",
            border: `1px solid ${i < setsDone ? stationColor : "#333"}`,
            transition: "all 0.3s",
          }} />
        ))}
      </div>
    </div>
  );
}

// ── Cronômetro principal ──────────────────────────────────────────────────
function ExerciseTimer({ exercise, totalSets, stationColor, onComplete }) {
  const wTime = exercise.workTime || WORK_TIME;
  // phase: "idle" | "work" | "rest" | "go"
  const [phase, setPhase] = useState("idle");
  const [timeLeft, setTimeLeft] = useState(wTime);
  const [setsDone, setSetsDone] = useState(0);
  const ref = useRef(null);

  // metrônomo só durante work
  useMetronome(phase === "work");

  // limpa ao desmontar
  useEffect(() => () => clearTimeout(ref.current), []);

  // tick
  useEffect(() => {
    if (phase !== "work" && phase !== "rest") return;
    if (timeLeft > 0) {
      ref.current = setTimeout(() => setTimeLeft((t) => t - 1), 1000);
    } else {
      if (phase === "work") {
        const next = setsDone + 1;
        setSetsDone(next);
        if (next >= totalSets) {
          setPhase("idle");
          onComplete && onComplete();
        } else {
          setPhase("rest");
          setTimeLeft(REST_TIME);
        }
      } else {
        // rest acabou → GO
        setPhase("go");
      }
    }
    return () => clearTimeout(ref.current);
  }, [phase, timeLeft]);

  const handleStart = () => {
    setPhase("work");
    setTimeLeft(wTime);
  };

  const handlePause = () => {
    clearTimeout(ref.current);
    setPhase("idle");
  };

  const handleGo = () => {
    setPhase("work");
    setTimeLeft(wTime);
  };

  // cores
  const isWork = phase === "work";
  const isRest = phase === "rest";
  const isGo   = phase === "go";
  const isIdle = phase === "idle";

  const timerColor = isWork ? "#E53E3E" : isRest ? "#3D8EF0" : isGo ? "#2ECC71" : "#404040";
  const total = isWork ? WORK_TIME : REST_TIME;
  const pct   = (phase === "go" || isIdle) ? (isGo ? 100 : 0)
              : ((total - timeLeft) / total) * 100;
  const r    = 72;
  const circ = 2 * Math.PI * r;

  return (
    <div style={{
      background: "#050505",
      border: `2px solid ${timerColor}50`,
      borderRadius: 24,
      padding: "24px 20px",
      textAlign: "center",
      boxShadow: `0 0 40px ${timerColor}15`,
      transition: "border-color 0.4s, box-shadow 0.4s",
    }}>
      {/* Nome */}
      <div style={{ fontSize: 20, fontWeight: 900, color: "#FFFFFF", letterSpacing: 1, marginBottom: 4 }}>
        {exercise.name}
      </div>
      <div style={{ fontSize: 12, color: "#4A4A4A", letterSpacing: 3, marginBottom: 20 }}>
        SÉRIE {Math.min(setsDone + 1, totalSets)} / {totalSets}
      </div>

      {/* Círculo SVG */}
      <div style={{ position: "relative", width: 190, height: 190, margin: "0 auto" }}>
        <svg width={190} height={190} style={{ transform: "rotate(-90deg)" }}>
          <circle cx={95} cy={95} r={r} fill="none" stroke="#1C1C1C" strokeWidth={11} />
          <circle
            cx={95} cy={95} r={r} fill="none"
            stroke={timerColor} strokeWidth={11}
            strokeDasharray={circ}
            strokeDashoffset={circ - (pct / 100) * circ}
            strokeLinecap="round"
            style={{ transition: "stroke-dashoffset 1s linear, stroke 0.4s" }}
          />
        </svg>

        {/* Conteúdo central */}
        <div style={{
          position: "absolute", inset: 0,
          display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center",
        }}>
          {isGo ? (
            <span style={{
              fontSize: 64, fontWeight: 900, color: "#2ECC71",
              fontFamily: "Barlow Condensed, sans-serif",
              animation: "goAnim 0.5s ease-in-out infinite alternate",
            }}>GO!</span>
          ) : isIdle && setsDone === 0 ? (
            <span style={{ fontSize: 38, color: "#333" }}>▶</span>
          ) : (
            <>
              <span style={{ fontSize: 54, fontWeight: 900, color: "#fff", fontFamily: "monospace", lineHeight: 1 }}>
                {String(timeLeft).padStart(2, "0")}
              </span>
              <span style={{ fontSize: 11, color: timerColor, letterSpacing: 2, marginTop: 4 }}>seg</span>
            </>
          )}
        </div>
      </div>

      {/* Label embaixo do círculo */}
      <div style={{
        fontSize: 16, fontWeight: 800, letterSpacing: 4,
        color: timerColor, textTransform: "uppercase",
        marginTop: 14, marginBottom: 20,
        transition: "color 0.4s",
        minHeight: 24,
      }}>
        {isWork ? "EXECUÇÃO" : isRest ? "INTERVALO" : isGo ? "HORA DE RECOMEÇAR!" : ""}
      </div>

      {/* Botões */}
      <div style={{ display: "flex", gap: 10 }}>
        {isGo && (
          <button onClick={handleGo} style={{
            flex: 1, padding: "16px", borderRadius: 14, cursor: "pointer",
            background: "#2ECC71", border: "none", color: "#000",
            fontSize: 22, fontWeight: 900, letterSpacing: 2,
            animation: "goAnim 0.5s ease-in-out infinite alternate",
          }}>🔥 GO!</button>
        )}
        {isWork && (
          <button onClick={handlePause} style={{
            flex: 1, padding: "14px", borderRadius: 14, cursor: "pointer",
            background: "#1C1C1C", border: "1px solid #333", color: "#BBBBBB",
            fontSize: 15, fontWeight: 700,
          }}>⏸ PAUSAR</button>
        )}
        {isRest && (
          <button onClick={handlePause} style={{
            flex: 1, padding: "14px", borderRadius: 14, cursor: "pointer",
            background: "#1C1C1C", border: "1px solid #333", color: "#BBBBBB",
            fontSize: 15, fontWeight: 700,
          }}>⏸ PAUSAR</button>
        )}
        {isIdle && !isGo && (
          <button onClick={handleStart} style={{
            flex: 1, padding: "16px", borderRadius: 14, cursor: "pointer",
            background: "#E53E3E", border: "none", color: "#ffffff",
            fontSize: 16, fontWeight: 800,
          }}>
            {setsDone === 0 ? "▶ INICIAR" : "▶ RETOMAR"}
          </button>
        )}
      </div>

      {/* Bolinhas de séries */}
      <div style={{ display: "flex", gap: 8, marginTop: 18, justifyContent: "center" }}>
        {Array.from({ length: totalSets }, (_, i) => (
          <div key={i} style={{
            width: 10, height: 10, borderRadius: "50%",
            background: i < setsDone ? (isWork && i === setsDone - 1 ? "#E53E3E" : stationColor) : "#232323",
            border: `1px solid ${i < setsDone ? stationColor : "#333"}`,
            transition: "all 0.3s",
          }} />
        ))}
      </div>
    </div>
  );
}

// ── Barra de progresso ────────────────────────────────────────────────────
function ProgressBar({ completed, total, color }) {
  return (
    <div style={{ background: "#1C1C1C", borderRadius: 99, height: 6, overflow: "hidden" }}>
      <div style={{
        height: "100%", borderRadius: 99, background: color,
        width: `${Math.min((completed / total) * 100, 100)}%`,
        transition: "width 0.4s ease",
        boxShadow: `0 0 8px ${color}`,
      }} />
    </div>
  );
}

// ── App principal ─────────────────────────────────────────────────────────
export default function App() {
  const [screen, setScreen] = useState("home");
  const [activeStation, setActiveStation] = useState(null);
  const [activePhase, setActivePhase] = useState("warmup");
  const [currentExIdx, setCurrentExIdx] = useState(0);
  const [completedExercises, setCompletedExercises] = useState([]);
  const [completedWarmup, setCompletedWarmup] = useState({});
  const [currentWeek, setCurrentWeek] = useState(1);

  const station = STATIONS.find((s) => s.id === activeStation);

  const startWorkout = (id) => {
    setActiveStation(id);
    setActivePhase("warmup");
    setCurrentExIdx(0);
    setCompletedExercises([]);
    setCompletedWarmup({});
    setScreen("workout");
  };

  const warmupDone = Object.values(completedWarmup).filter(Boolean).length;

  // avança para próximo exercício
  const handleExerciseDone = () => {
    const next = currentExIdx + 1;
    setCompletedExercises((prev) => [...prev, currentExIdx]);
    if (station && next >= station.exercises.length) {
      setActivePhase("finish");
    } else {
      setCurrentExIdx(next);
    }
  };

  return (
    <div style={{
      minHeight: "100vh", background: "#080808", color: "#fff",
      fontFamily: "\'Barlow Condensed\', \'Arial Narrow\', Arial, sans-serif",
      overflowX: "hidden",
    }}>
      <style>{`
        @import url(\'https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@400;600;700;800;900&family=Barlow:wght@400;500;600&family=Oswald:wght@400;500;600;700&display=swap\');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        ::-webkit-scrollbar { width: 3px; }
        ::-webkit-scrollbar-track { background: #0a0a0a; }
        ::-webkit-scrollbar-thumb { background: #2a2a2a; border-radius: 99px; }
        .card-hover { transition: transform 0.18s cubic-bezier(.4,0,.2,1), box-shadow 0.18s; }
        .card-hover:active { transform: scale(0.97); }
        .card-hover:hover { transform: translateY(-1px); }
        @keyframes goAnim { from { transform: scale(1); opacity: 1; } to { transform: scale(1.08); opacity: 0.9; } }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: translateY(0); } }
        .fade-in { animation: fadeIn 0.3s ease forwards; }
      `}</style>

      {/* ════════════════ HOME ════════════════ */}
      {screen === "home" && (
        <div style={{ maxWidth: 480, margin: "0 auto", paddingBottom: 80 }}>
          {/* Hero */}
          <div style={{
            background: "linear-gradient(180deg, #0a0a0a 0%, #080808 100%)",
            padding: "40px 24px 32px", textAlign: "center",
            borderBottom: "1px solid #1a1a1a", position: "relative", overflow: "hidden",
          }}>
            <div style={{
              position: "absolute", top: -60, left: "50%", transform: "translateX(-50%)",
              width: 300, height: 300, borderRadius: "50%",
              background: "radial-gradient(circle, rgba(249,115,22,0.08) 0%, transparent 70%)",
            }} />
            <img
              src={`data:image/png;base64,${LOGO_B64}`}
              alt="Método 4K"
              style={{ width: "100%", maxWidth: 300, display: "block", margin: "0 auto 14px" }}
            />
            <div style={{
              display: "inline-block", background: "#2ECC71", color: "#000",
              fontSize: 11, fontWeight: 800, letterSpacing: 3, padding: "4px 14px",
              borderRadius: 99, marginBottom: 10, textTransform: "uppercase",
            }}>FUTHIT</div>
            <div style={{ color: "#F1C40F", fontSize: 13, letterSpacing: 1, fontFamily: "Barlow, sans-serif" }}>
              FORÇA · EXPLOSÃO · RESISTÊNCIA · PERFORMANCE
            </div>
            <div style={{ display: "flex", gap: 10, justifyContent: "center", marginTop: 24 }}>
              {[["3x", "treinos/sem"], ["45s", "por série"], ["8", "semanas"]].map(([v, l]) => (
                <div key={l} style={{
                  background: "#161616", border: "1px solid #1e1e1e",
                  borderRadius: 14, padding: "12px 16px", textAlign: "center",
                }}>
                  <div style={{ fontSize: 26, fontWeight: 900, color: "#2ECC71" }}>{v}</div>
                  <div style={{ fontSize: 10, color: "#4A4A4A", letterSpacing: 1 }}>{l.toUpperCase()}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Semana */}
          <div style={{ padding: "22px 20px 0" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
              <span style={{ fontSize: 12, color: "#F1C40F", letterSpacing: 2, textTransform: "uppercase" }}>Semana atual</span>
              <span style={{ fontSize: 20, fontWeight: 900, color: "#FFFFFF" }}>{currentWeek} <span style={{ fontSize: 12, color: "#404040" }}>/ 8</span></span>
            </div>
            <ProgressBar completed={currentWeek} total={8} color="#2ECC71" />
            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 8 }}>
              <button onClick={() => setCurrentWeek((w) => Math.max(1, w - 1))}
                style={{ background: "#161616", border: "1px solid #222", color: "#fff", padding: "6px 16px", borderRadius: 8, cursor: "pointer", fontSize: 18 }}>‹</button>
              <span style={{ fontSize: 11, color: "#404040", alignSelf: "center" }}>
                {STATIONS.find(s => currentWeek <= s.id * 2 && currentWeek > (s.id - 1) * 2)?.name || "CICLO COMPLETO"}
              </span>
              <button onClick={() => setCurrentWeek((w) => Math.min(8, w + 1))}
                style={{ background: "#161616", border: "1px solid #222", color: "#fff", padding: "6px 16px", borderRadius: 8, cursor: "pointer", fontSize: 18 }}>›</button>
            </div>
          </div>

          {/* Estações */}
          <div style={{ padding: "24px 20px 0" }}>
            <div style={{ fontSize: 11, color: "#F1C40F", letterSpacing: 3, textTransform: "uppercase", marginBottom: 14 }}>Estações do ciclo</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {STATIONS.map((s) => {
                const isActive = currentWeek <= s.id * 2 && currentWeek > (s.id - 1) * 2;
                return (
                  <button key={s.id} className="card-hover" onClick={() => startWorkout(s.id)}
                    style={{
                      background: isActive ? "linear-gradient(135deg, #161616 0%, #111111 100%)" : "#0D0D0D",
                      border: `1px solid ${isActive ? s.color + "40" : "#1E1E1E"}`,
                      borderRadius: 18, padding: "18px", cursor: "pointer", textAlign: "left",
                      boxShadow: isActive ? `0 0 20px ${s.color}12` : "none",
                      position: "relative", overflow: "hidden",
                    }}>
                    {isActive && (
                      <div style={{
                        position: "absolute", top: 0, right: 0, background: s.color,
                        color: "#000", fontSize: 9, fontWeight: 800, padding: "4px 10px",
                        borderBottomLeftRadius: 10, letterSpacing: 1.5,
                      }}>ATUAL</div>
                    )}
                    <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
                      <div style={{
                        width: 48, height: 48, borderRadius: 14,
                        background: `${s.color}15`, border: `1px solid ${s.color}30`,
                        display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 24, flexShrink: 0,
                      }}>{s.emoji}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ display: "flex", alignItems: "baseline", gap: 8 }}>
                          <span style={{ fontSize: 20, fontWeight: 900, color: s.color }}>{s.name}</span>
                          <span style={{ fontSize: 13, color: "#4A4A4A" }}>{s.subtitle}</span>
                        </div>
                        <div style={{ fontSize: 11, color: "#404040", marginTop: 2 }}>{s.weeks}</div>
                      </div>
                      <div style={{
                        width: 30, height: 30, borderRadius: "50%",
                        background: `${s.color}20`, border: `1px solid ${s.color}40`,
                        display: "flex", alignItems: "center", justifyContent: "center",
                        color: s.color, fontSize: 16,
                      }}>›</div>
                    </div>
                    <div style={{ marginTop: 12, fontSize: 12, color: "#404040", fontFamily: "Barlow, sans-serif", lineHeight: 1.5 }}>
                      {s.objective}
                    </div>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Dicas */}
          <div style={{ padding: "24px 20px 0" }}>
            <div style={{ fontSize: 11, color: "#F1C40F", letterSpacing: 3, textTransform: "uppercase", marginBottom: 12 }}>Dicas</div>
            <div style={{ background: "#0D0D0D", border: "1px solid #181818", borderRadius: 16, padding: "16px" }}>
              {TIPS.map((t, i) => (
                <div key={i} style={{
                  display: "flex", gap: 10, alignItems: "flex-start",
                  paddingBottom: i < TIPS.length - 1 ? 10 : 0,
                  marginBottom: i < TIPS.length - 1 ? 10 : 0,
                  borderBottom: i < TIPS.length - 1 ? "1px solid #151515" : "none",
                }}>
                  <span style={{ color: "#2ECC71", fontSize: 14, flexShrink: 0 }}>✓</span>
                  <span style={{ fontSize: 12, color: "#505050", fontFamily: "Barlow, sans-serif", lineHeight: 1.5 }}>{t}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ════════════════ WORKOUT ════════════════ */}
      {screen === "workout" && station && (
        <div style={{ maxWidth: 480, margin: "0 auto", paddingBottom: 80 }}>
          {/* Header fixo */}
          <div style={{
            background: "#080808cc", padding: "14px 20px",
            borderBottom: "1px solid #151515", position: "sticky", top: 0, zIndex: 100,
            backdropFilter: "blur(14px)",
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <button onClick={() => setScreen("home")} style={{
                background: "#161616", border: "1px solid #222", color: "#fff",
                width: 38, height: 38, borderRadius: 12, cursor: "pointer", fontSize: 18,
                display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0,
              }}>‹</button>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 18, fontWeight: 900, color: station.color }}>
                  ESTAÇÃO {station.id} – {station.name}
                </div>
                <div style={{ fontSize: 11, color: "#404040" }}>{station.weeks}</div>
              </div>
              <div style={{ fontSize: 26 }}>{station.emoji}</div>
            </div>
            {/* Abas */}
            <div style={{ display: "flex", gap: 6, marginTop: 12 }}>
              {[["warmup","Aquecimento"], ["main","Treino"], ["finish","Finalização"]].map(([p, l]) => (
                <button key={p} onClick={() => {
                  setActivePhase(p);
                  if (p === "main") { setCurrentExIdx(0); setCompletedExercises([]); }
                }} style={{
                  flex: 1, padding: "7px 4px", borderRadius: 10, cursor: "pointer", fontSize: 11,
                  fontWeight: 700, letterSpacing: 0.5,
                  background: activePhase === p ? station.color : "#161616",
                  color: activePhase === p ? "#000" : "#404040",
                  border: `1px solid ${activePhase === p ? station.color : "#232323"}`,
                  transition: "all 0.2s",
                }}>{l}</button>
              ))}
            </div>
          </div>

          <div style={{ padding: "20px" }}>

            {/* ── AQUECIMENTO ── */}
            {activePhase === "warmup" && (
              <div>
                <WarmupTimer
                  key={activeStation}
                  warmupList={station.warmup}
                  stationColor={station.color}
                  onComplete={() => {
                    setCompletedWarmup(
                      Object.fromEntries(station.warmup.map((_, i) => [i, true]))
                    );
                  }}
                />
                <button
                  onClick={() => setActivePhase("main")}
                  style={{
                    width: "100%", marginTop: 16, padding: "16px",
                    borderRadius: 14, cursor: "pointer",
                    background: station.color, border: "none", color: "#000",
                    fontSize: 17, fontWeight: 900, letterSpacing: 1,
                  }}
                >IR PARA O TREINO →</button>
              </div>
            )}

            {/* ── TREINO CRONOMETRADO ── */}
            {activePhase === "main" && station.exercises[currentExIdx] && (
              <div>
                {/* Barra progresso geral */}
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                  <span style={{ fontSize: 11, color: "#4A4A4A", letterSpacing: 2, textTransform: "uppercase" }}>Exercício</span>
                  <span style={{ fontSize: 12, color: station.color, fontWeight: 700 }}>
                    {currentExIdx + 1} / {station.exercises.length}
                  </span>
                </div>
                <ProgressBar completed={currentExIdx} total={station.exercises.length} color={station.color} />

                {/* Lista de exercícios (mini navegação) */}
                <div style={{ display: "flex", gap: 6, marginTop: 14, marginBottom: 20, overflowX: "auto", paddingBottom: 4 }}>
                  {station.exercises.map((ex, i) => (
                    <button key={i} onClick={() => setCurrentExIdx(i)} style={{
                      flexShrink: 0, padding: "6px 12px", borderRadius: 99, cursor: "pointer",
                      fontSize: 11, fontWeight: 700,
                      background: i === currentExIdx ? station.color
                                : completedExercises.includes(i) ? `${station.color}20` : "#161616",
                      color: i === currentExIdx ? "#000"
                           : completedExercises.includes(i) ? station.color : "#404040",
                      border: `1px solid ${i === currentExIdx ? station.color
                              : completedExercises.includes(i) ? station.color + "40" : "#222"}`,
                    }}>
                      {completedExercises.includes(i) ? "✓ " : ""}{i + 1}
                    </button>
                  ))}
                </div>

                {/* Cronômetro — bilateral/plank ou padrão */}
                {station.exercises[currentExIdx].bilateral || station.exercises[currentExIdx].plank ? (
                  <BilateralTimer
                    key={currentExIdx}
                    exercise={station.exercises[currentExIdx]}
                    totalSets={station.exercises[currentExIdx].sets}
                    stationColor={station.color}
                    onComplete={handleExerciseDone}
                  />
                ) : (
                  <ExerciseTimer
                    key={currentExIdx}
                    exercise={station.exercises[currentExIdx]}
                    totalSets={station.exercises[currentExIdx].sets}
                    stationColor={station.color}
                    onComplete={handleExerciseDone}
                  />
                )}

                {/* Botão próximo manual */}
                {currentExIdx < station.exercises.length - 1 && (
                  <button onClick={handleExerciseDone} style={{
                    width: "100%", marginTop: 14, padding: "14px", borderRadius: 14, cursor: "pointer",
                    background: "transparent", border: `1px solid #222`, color: "#4A4A4A",
                    fontSize: 13, fontWeight: 700,
                  }}>Pular para próximo exercício →</button>
                )}
              </div>
            )}

            {/* ── FINALIZAÇÃO ── */}
            {activePhase === "finish" && (
              <div style={{ textAlign: "center" }}>
                <div style={{
                  background: "#0D0D0D", border: `1px solid ${station.color}30`,
                  borderRadius: 20, padding: "32px 24px", marginBottom: 18,
                }}>
                  <div style={{ fontSize: 56, marginBottom: 14 }}>🔥</div>
                  <div style={{ fontSize: 30, fontWeight: 900, color: station.color, marginBottom: 8 }}>TREINO CONCLUÍDO!</div>
                  <div style={{ fontSize: 14, color: "#777", fontFamily: "Barlow, sans-serif", lineHeight: 1.6 }}>{station.finish}</div>
                </div>
                <button onClick={() => setScreen("home")} style={{
                  width: "100%", padding: "18px", borderRadius: 16, cursor: "pointer",
                  background: station.color, border: "none", color: "#000",
                  fontSize: 18, fontWeight: 900, letterSpacing: 1,
                }}>✓ VOLTAR AO INÍCIO</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
